import { NextResponse } from "next/server";
import Groq from "groq-sdk";
import webSearch from "../../utils/webSearch";

const client = new Groq({
    apiKey: process.env.GROQ_API_KEY, // safe on server
});

export async function POST(req: Request) {
    try {
        const { prompt } = await req.json();
        const messages = [
            {
                role: "system",
                content: "You are Clara, a helpful smart assistant. When users ask about recent events, current information, or real-time data, use the webSearch tool to find the latest information. Always provide accurate and helpful responses.",
            },
            {
                role: "user",
                content: prompt,
            },
        ];

        let finalResponse = "";
        while (true) {
            const chatCompletion = await client.chat.completions.create({
                // response_format: {type: "json_object"},
                model: "llama-3.3-70b-versatile",
                messages: messages,
                "tools": [
                    {
                        "type": "function",
                        "function": {
                            "name": "webSearch",
                            "description": "Search the latest information and realtime data on the internet using Tavily API",
                            "parameters": {
                                "type": "object",
                                "properties": {
                                    "query": {
                                        "type": "string",
                                        "description": "The search query string to search on the web"
                                    }
                                },
                                "required": ["query"],
                                "additionalProperties": false
                            }
                        }
                    }
                ],
                tool_choice: 'auto'
            });

            const choice = chatCompletion.choices[0]?.message;
            if (!choice) {
                console.error("No choices returned in chat completion:", chatCompletion);
                return NextResponse.json({ error: "No response from model" }, { status: 500 });
            }
            messages.push(choice); // add assistant's message to the conversation history

            // If no tool calls, break the loop and return the response
            if (!choice?.tool_calls || choice.tool_calls.length === 0) {
                finalResponse = choice?.content || "";
                break;
            }

            // Handle tool calls
            for (const tool of choice?.tool_calls || []) {
                const functionName = tool?.function?.name;
                const functionParams = tool?.function?.arguments;

                if (functionName === "webSearch") {
                    try {
                        // Call the actual function and get result
                        const params = typeof functionParams === "string" ? JSON.parse(functionParams) : functionParams;
                        const searchResult = await webSearch(params.query);
                        console.log(`Tool call result for ${functionName}:`, searchResult);
                        const toolResult = JSON.stringify(searchResult);

                        messages.push({
                            role: "tool",
                            tool_call_id: tool.id,
                            name: functionName,
                            content: toolResult,
                        } as any); // add tool response to conversation history        
                    } catch (toolErr: any) {
                        console.error(`Error executing tool ${functionName}:`, toolErr);
                    }
                }
            }
        }

        return NextResponse.json({
            text: finalResponse,
        });
    } catch (error: any) {
        console.error("Groq API error:", error);
        return NextResponse.json({ error: error.message }, { status: 500 });
    }
}