import { tavily } from "@tavily/core";
// import Groq from "groq-sdk";

const tvly = tavily({
    apiKey: process.env.TAVILY_API_KEY, // safe on server
    // Optionally specify a custom API base URL if needed
    // apiBaseUrl: "https://api.tavily.com/v1",
}); 

async function webSearch(query) {

    console.log(`Performing web search for query: ${query}`);
    const response = await tvly.search(query);
    console.log(`Web search response for query "${query}":`, response);
    const finalResponse = response.results.map(result => result.content).join("\n\n");
    return finalResponse;
}

export default webSearch;